import React, { useState } from "react";
import UploadBox from "../components/UploadBox";
import ResultCard from "../components/ResultCard";

function Home() {
  const [data, setData] = useState(null);

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">AI Internship Recommendation Engine</h1>

      <UploadBox setData={setData} />

      {data && (
        <>
          <h4>Detected Skills: {data.skills.join(", ")}</h4>

          <div className="mt-4">
            {data.recommendations.map((job, i) => (
              <ResultCard key={i} job={job} />
            ))}
          </div>
        </>
      )}
    </div>
  );
}

export default Home;
